import { Box, Button, Container, Grid, Link, TextField, Typography } from '@mui/material';
import React, { useRef, useState } from "react";
import Layout from "../components/Layout";
import useUser from "../storage/useUser";
import ReCAPTCHA from "react-google-recaptcha";
import api from '../components/api';
import { CAPTCHA_KEY } from '../utils/utils';

export default function Contato() {
    const recaptchaRef = React.useRef() as any;

    const [formData, setFormData] = useState({
        name: '',
        email: '',
        phone: '',
        subject: '',
        message: '',
    })
    const { login } = useUser();

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setFormData({ ...formData, [name]: value });
    };

    const handleSubmit = async(e: React.FormEvent) => {
        e.preventDefault();
        let token;
        if (recaptchaRef && recaptchaRef.current) {
            token = await recaptchaRef?.current.executeAsync();
        }

        if (!token) {
            alert("Verifique o reCAPTCHA");
        }
        else {
            api.post("/v1/contact", {
                captchaResponse: token,
                name: formData.name,
                email: formData.email,
                phone: formData.phone || null,
                subject: formData.subject,
                message: formData.message,
            })
                .then(() => {
                    // TODO: dialog
                    alert('Mensagem enviada com sucesso! Iremos responder em breve.')
                }).catch((e) => {
                    console.log(e);
                    alert('Houve um erro, tente mais tarde.')
                });
        }
    };


    return (
        <Layout>
            <Container maxWidth="sm">
                <Box mt={5} mb={5}>
                    <form onSubmit={handleSubmit}>
                        <Grid container spacing={2}>
                            <Grid item xs={12}>
                                <Typography variant="h4" align="center" gutterBottom>
                                    Fale Conosco
                                </Typography>
                                <Typography variant="caption" display="block" gutterBottom>
                                    Estamos aqui para ajudar! Por favor, preencha o formulário abaixo com sua dúvida, sugestão ou qualquer outra questão. Nossa equipe entrará em contato em até um dia útil.
                                </Typography>
                            </Grid>
                            <Grid item xs={12} sm={12}>
                                <TextField
                                    fullWidth
                                    label="Nome"
                                    name="name"
                                    value={formData.name}
                                    onChange={handleChange}
                                    inputProps={{ maxLength: 255 }}
                                    required
                                />
                            </Grid>
                            <Grid item xs={12} sm={6}>
                                <TextField
                                    fullWidth
                                    label="Email"
                                    type="email"
                                    name="email"
                                    value={formData.email}
                                    onChange={handleChange}
                                    inputProps={{ maxLength: 255 }}
                                    required
                                />
                            </Grid>
                            <Grid item xs={12} sm={6}>
                                <TextField
                                    fullWidth
                                    label="Telefone (opcional)"
                                    name="phone"
                                    value={formData.phone}
                                    inputProps={{ maxLength: 11 }}
                                    onChange={handleChange}
                                />
                            </Grid>
                            <Grid item xs={12}>
                                <TextField
                                    fullWidth
                                    label="Assunto"
                                    name="subject"
                                    value={formData.subject}
                                    onChange={handleChange}
                                    inputProps={{ maxLength: 255 }}
                                    required
                                />
                            </Grid>
                            <Grid item xs={12}>
                                <TextField
                                    fullWidth
                                    label="Mensagem"
                                    multiline
                                    rows={4}
                                    inputProps={{ maxLength: 500 }}
                                    name="message"
                                    value={formData.message}
                                    onChange={handleChange}
                                    required
                                />
                                <Typography>
                                    {`${formData.message.length}/500`}
                                </Typography>
                            </Grid>
                            <Grid item xs={12}>
                                <ReCAPTCHA
                                    ref={recaptchaRef}
                                    size="invisible"
                                    sitekey={CAPTCHA_KEY}
                                />
                            </Grid>
                            <Grid item xs={12}>
                                <Typography variant="body2" gutterBottom>
                                    Ao enviar a mensagem, você concorda com a <Link href="/politica-de-privacidade">política de privacidade</Link>.
                                </Typography>
                            </Grid>
                            <Grid item xs={12}>
                                <Button type="submit" size="large" variant="contained" color="primary" fullWidth>
                                    Enviar mensagem
                                </Button>
                            </Grid>
                        </Grid>
                    </form>
                </Box>
            </Container>
        </Layout>
    );
}
